import{c as e}from"./createSolutionPack-C_Q4-4X6.js";import"./index-CMPoedmy.js";const s=[[{steps:["Euclid's Division Lemma states that for any two positive integers a and b, there exist unique integers q and r such that a = bq + r.","The remainder must satisfy 0 <= r < b."],finalAnswer:"Answer: a = bq + r, where 0 <= r < b and q, r are unique integers."},{steps:["45 = 6 x 7 + 3.","So the remainder left after dividing 45 by 6 is 3."],finalAnswer:"Answer: Remainder = 3."},{steps:["17 has only two factors: 1 and 17.","A number with exactly two factors is called a prime number."],finalAnswer:"Answer: Yes, 17 is a prime number."},{steps:["12 = 2^2 x 3.","16 = 2^4.","The common prime factor with the smallest power is 2^2."],finalAnswer:"Answer: HCF(12, 16) = 4."},{steps:["4 = 2^2 and 6 = 2 x 3.","Take each prime factor with the highest power: 2^2 x 3."],finalAnswer:"Answer: LCM(4, 6) = 12."},{steps:["20 = 2 x 10.","10 = 2 x 5.","Therefore, 20 = 2 x 2 x 5 = 2^2 x 5."],finalAnswer:"Answer: Prime factors of 20 are 2 x 2 x 5."},{steps:["1/8 is already in lowest form.","8 = 2^3, so the denominator has only the prime factor 2.","A denominator of the form 2^n x 5^m gives a terminating decimal."],finalAnswer:"Answer: 1/8 has a terminating decimal expansion."},{steps:["0.25 = 25/100.","Divide numerator and denominator by 25.","25/100 = 1/4."],finalAnswer:"Answer: 0.25 = 1/4."},{steps:["15 = 3 x 5.","25 = 5 x 5.","The common prime factor is 5."],finalAnswer:"Answer: HCF(15, 25) = 5."},{steps:["Irrational numbers cannot be written in the form p/q.","Common examples are square roots of non-perfect squares and pi."],finalAnswer:"Answer: Two irrational numbers are sqrt(2) and sqrt(3)."}],[{steps:["225 = 135 x 1 + 90","135 = 90 x 1 + 45","90 = 45 x 2 + 0","When the remainder becomes 0, the last divisor is the HCF."],finalAnswer:"Answer: HCF(135, 225) = 45."},{steps:["18 = 2 x 3^2 and 24 = 2^3 x 3.","HCF uses the smallest powers: 2 x 3 = 6.","LCM uses the highest powers: 2^3 x 3^2 = 72."],finalAnswer:"Answer: HCF = 6 and LCM = 72."},{steps:["For 6 and 8, HCF = 2.","LCM = 24.","HCF x LCM = 2 x 24 = 48.","Product of the numbers = 6 x 8 = 48."],finalAnswer:"Answer: Verified, because HCF x LCM = 48 = product of the numbers."},{steps:["144 = 12 x 12.","12 = 2^2 x 3, so 144 = (2^2 x 3)(2^2 x 3).","Therefore, 144 = 2^4 x 3^2."],finalAnswer:"Answer: Prime factorization of 144 is 2^4 x 3^2."},{steps:["7/50 is already in lowest form.","50 = 2 x 5^2.","Since the denominator has only 2 and 5 as prime factors, the decimal terminates."],finalAnswer:"Answer: 7/50 is terminating."},{steps:["36 = 2^2 x 3^2.","54 = 2 x 3^3.","Take common prime factors with smallest powers: 2 x 3^2."],finalAnswer:"Answer: HCF(36, 54) = 18."},{steps:["0.125 = 125/1000.","Divide numerator and denominator by 125.","125/1000 = 1/8."],finalAnswer:"Answer: 0.125 = 1/8."},{steps:["12 = 2^2 x 3 and 15 = 3 x 5.","Take highest powers of all prime factors: 2^2 x 3 x 5."],finalAnswer:"Answer: LCM(12, 15) = 60."},{steps:["sqrt(3) cannot be written in the form p/q.","Its decimal expansion is non-terminating and non-recurring."],finalAnswer:"Answer: sqrt(3) is irrational."},{steps:["27 = 3^3.","36 = 2^2 x 3^2.","The common prime factor with smallest power is 3^2."],finalAnswer:"Answer: HCF(27, 36) = 9."}],[{steps:["867 = 255 x 3 + 102","255 = 102 x 2 + 51","102 = 51 x 2 + 0","The last non-zero remainder divisor is 51."],finalAnswer:"Answer: HCF(867, 255) = 51."},{steps:["72 = 2^3 x 3^2 and 120 = 2^3 x 3 x 5.","HCF = 2^3 x 3 = 24.","LCM = 2^3 x 3^2 x 5 = 360."],finalAnswer:"Answer: HCF = 24 and LCM = 360."},{steps:["20 = 2^2 x 5 and 30 = 2 x 3 x 5.","HCF = 2 x 5 = 10 and LCM = 2^2 x 3 x 5 = 60.","HCF x LCM = 10 x 60 = 600.","Product of the numbers = 20 x 30 = 600."],finalAnswer:"Answer: HCF x LCM = product of the numbers, so the identity is proved."},{steps:["13/3125 is already in lowest form.","3125 = 5^5.","Since the denominator has only 5 as a prime factor, the decimal expansion terminates."],finalAnswer:"Answer: 13/3125 is terminating."},{steps:["657 = 306 x 2 + 45","306 = 45 x 6 + 36","45 = 36 x 1 + 9","36 = 9 x 4 + 0"],finalAnswer:"Answer: HCF(306, 657) = 9."},{steps:["630 = 63 x 10.","63 = 3^2 x 7 and 10 = 2 x 5.","So 630 = 2 x 3^2 x 5 x 7."],finalAnswer:"Answer: Prime factorization of 630 is 2 x 3^2 x 5 x 7."},{steps:["Find the LCM of 6, 8, and 12.","6 = 2 x 3, 8 = 2^3, 12 = 2^2 x 3.","Take highest powers: 2^3 x 3 = 24."],finalAnswer:"Answer: The smallest number divisible by 6, 8, and 12 is 24."},{steps:["0.375 = 375/1000.","Divide numerator and denominator by 125.","375/1000 = 3/8."],finalAnswer:"Answer: 0.375 = 3/8."},{steps:["7/45 is already in lowest form.","45 = 3^2 x 5.","Because the denominator contains 3 as a prime factor other than 2 or 5, the decimal does not terminate."],finalAnswer:"Answer: 7/45 is non-terminating recurring."},{steps:["56 = 2^3 x 7.","98 = 2 x 7^2.","Common prime factors with smallest powers give 2 x 7."],finalAnswer:"Answer: HCF(56, 98) = 14."}],[{steps:["54321 = 12345 x 4 + 4941","12345 = 4941 x 2 + 2463","4941 = 2463 x 2 + 15","2463 = 15 x 164 + 3","15 = 3 x 5 + 0"],finalAnswer:"Answer: HCF(12345, 54321) = 3."},{steps:["24 = 2^3 x 3, 36 = 2^2 x 3^2, and 54 = 2 x 3^3.","Take the highest powers of each prime factor.","LCM = 2^3 x 3^3 = 216."],finalAnswer:"Answer: LCM(24, 36, 54) = 216."},{steps:["Assume sqrt(5) is rational, so sqrt(5) = p/q in lowest form where q is not 0.","Squaring both sides gives 5q^2 = p^2, so p^2 is divisible by 5 and hence p is divisible by 5.","Let p = 5k. Then 5q^2 = 25k^2, so q^2 = 5k^2 and q is also divisible by 5.","This means p and q have a common factor 5, which contradicts the assumption that p/q is in lowest form."],finalAnswer:"Answer: Therefore, sqrt(5) is irrational."},{steps:["If a number leaves remainder 9 when dividing both 306 and 657, subtract 9 from each number.","306 - 9 = 297 and 657 - 9 = 648.","Now find HCF(297, 648): 648 = 297 x 2 + 54, 297 = 54 x 5 + 27, 54 = 27 x 2 + 0."],finalAnswer:"Answer: The greatest required number is 27."},{steps:["96 = 2^5 x 3","144 = 2^4 x 3^2","192 = 2^6 x 3","Use the common prime factors with the smallest powers: 2^4 x 3."],finalAnswer:"Answer: HCF(96, 144, 192) = 48."},{steps:["Find the LCM of 8, 12, and 15.","8 = 2^3, 12 = 2^2 x 3, 15 = 3 x 5.","Take highest powers: 2^3 x 3 x 5 = 120."],finalAnswer:"Answer: The least number divisible by 8, 12, and 15 is 120."},{steps:["For two numbers, first number x second number = HCF x LCM.","So the other number = (12 x 180)/36 = 60.","Check: HCF(36, 60) = 12 and LCM(36, 60) = 180."],finalAnswer:"Answer: The other number is 60."},{steps:["Let the two consecutive numbers be n and n + 1.","Among any two consecutive integers, one is always even.","If one factor is even, the product n(n + 1) is divisible by 2."],finalAnswer:"Answer: The product of two consecutive numbers is always divisible by 2."},{steps:["77/210 = 11/30 after dividing numerator and denominator by 7.","30 = 2 x 3 x 5.","Since the denominator contains 3, the decimal expansion is not terminating."],finalAnswer:"Answer: 77/210 is non-terminating recurring."},{steps:["Let x = 0.123123...","Then 1000x = 123.123123...","Subtract: 1000x - x = 123.123123... - 0.123123...","999x = 123, so x = 123/999 = 41/333."],finalAnswer:"Answer: 0.123123... = 41/333."},{steps:["The smallest number divisible by 3, 5, and 7 is their LCM.","Since 3, 5, and 7 are pairwise prime, LCM = 3 x 5 x 7."],finalAnswer:"Answer: The smallest number is 105."},{steps:["Assume sqrt(7) is rational, so sqrt(7) = p/q in lowest form.","Squaring gives 7q^2 = p^2, so p is divisible by 7.","Let p = 7k. Then 7q^2 = 49k^2, so q^2 = 7k^2 and q is also divisible by 7.","This contradicts the assumption that p and q have no common factor."],finalAnswer:"Answer: Therefore, sqrt(7) is irrational."},{steps:["45 = 3^2 x 5, 60 = 2^2 x 3 x 5, and 75 = 3 x 5^2.","Take highest powers of all prime factors: 2^2 x 3^2 x 5^2."],finalAnswer:"Answer: LCM(45, 60, 75) = 900."},{steps:["To find HCF of three numbers by Euclid method, first find the HCF of any two numbers.","Then use Euclid algorithm again with that HCF and the third number.","The last non-zero divisor in the second stage is the HCF of all three numbers."],finalAnswer:"Answer: First find HCF of two numbers, then find HCF of that result with the third number."},{steps:["If a number leaves remainder 5 when divided by 12 and 15, subtract 5 first.","Then the remaining number must be divisible by both 12 and 15.","LCM(12, 15) = 60, so the required number is 60 + 5."],finalAnswer:"Answer: The least required number is 65."},{steps:["In the chapter context, terminating decimals depend on the denominator in lowest form.","A denominator of the form 2^n x 5^m has no prime factors other than 2 and 5.","Therefore, any rational number with denominator 2^n x 5^m has a terminating decimal expansion."],finalAnswer:"Answer: Yes. A denominator of the form 2^n x 5^m always gives a terminating decimal."},{steps:["Let an odd number be 2n + 1.","Its square is (2n + 1)^2 = 4n^2 + 4n + 1.","This can be written as 2(2n^2 + 2n) + 1, which is of the form 2k + 1."],finalAnswer:"Answer: Hence, the square of any odd number is odd."},{steps:["If the same remainder is left on dividing 125 and 145, then the divisor must divide their difference.","145 - 125 = 20.","The greatest divisor of 20 that works is 20 itself.","Check: 125 leaves remainder 5 and 145 also leaves remainder 5 when divided by 20."],finalAnswer:"Answer: The largest number is 20."},{steps:["1024 = 2^10.","640 = 2^7 x 5.","The common prime factor with the smallest power is 2^7."],finalAnswer:"Answer: HCF(1024, 640) = 128."},{steps:["Let x = 0.272727...","Then 100x = 27.272727...","Subtract: 100x - x = 27.272727... - 0.272727...","99x = 27, so x = 27/99 = 3/11."],finalAnswer:"Answer: 0.272727... = 3/11."}]],i=e("mathematics","real-numbers","Detailed worked answers for every Real Numbers practice question, arranged in the same order as the chapter practice set.",s);export{i as chapterSolutions};
